sql:
SELECT COUNT(*) AS total_stops
FROM stops
WHERE driver_id = (SELECT MAX(driver_id) FROM drivers);

SELECT COUNT(DISTINCT stop_id) AS total_stops
FROM stop_history
WHERE history_type = 'arrest';

SELECT search_id, search_type 
FROM search_conducted 
WHERE search_type IN ('Evidence', 'Inventory');

SELECT AVG(sd.stop_duration) AS average_duration
FROM stops s
JOIN stop_durations sd ON s.duration_id = sd.duration_id;

